.PHONY: help test lint build install clean check benchmark coverage

# 색상 정의
BLUE := \033[0;34m
GREEN := \033[0;32m
RED := \033[0;31m
NC := \033[0m

# 기본 변수
PYTHON := python3
SHELL := /bin/bash
PROJECT_NAME := termux-essential-tools
VERSION := 1.0.0

help:
	@echo "$(BLUE)==== Termux Essential Tools Makefile ====$(NC)"
	@echo ""
	@echo "$(GREEN)Available targets:$(NC)"
	@echo "  make test              - Run all tests"
	@echo "  make test-unit         - Run unit tests only"
	@echo "  make test-integration  - Run integration tests"
	@echo "  make test-e2e          - Run end-to-end tests"
	@echo "  make lint              - Run code quality checks"
	@echo "  make coverage          - Generate coverage report"
	@echo "  make benchmark         - Run performance benchmarks"
	@echo "  make build             - Build the project"
	@echo "  make install           - Install the project"
	@echo "  make clean             - Clean build artifacts"
	@echo "  make check             - Run all checks"
	@echo "  make help              - Show this message"
	@echo ""

# ============================================================================
# 테스트 타겟
# ============================================================================

test: test-unit test-integration
	@echo "$(GREEN)[SUCCESS]$(NC) All tests completed"

test-unit:
	@echo "$(BLUE)Running unit tests...$(NC)"
	@find tests -name "test_*.sh" | while read test; do \
		echo "Running $$test..."; \
		bash "$$test" || exit 1; \
	done
	@if command -v pytest &>/dev/null; then \
		pytest tests/test_*.py -v; \
	fi

test-integration:
	@echo "$(BLUE)Running integration tests...$(NC)"
	@if [[ -f tests/integration_test.sh ]]; then \
		bash tests/integration_test.sh; \
	fi

test-e2e:
	@echo "$(BLUE)Running E2E tests...$(NC)"
	@if [[ -f tests/e2e_test.sh ]]; then \
		bash tests/e2e_test.sh; \
	fi

# ============================================================================
# 코드 품질 타겟
# ============================================================================

lint: lint-shell lint-python
	@echo "$(GREEN)[SUCCESS]$(NC) Linting completed"

lint-shell:
	@echo "$(BLUE)Linting shell scripts...$(NC)"
	@if command -v shellcheck &>/dev/null; then \
		find . -name "*.sh" -type f | while read script; do \
			shellcheck "$$script" || exit 1; \
		done; \
	else \
		echo "$(RED)WARNING:$(NC) shellcheck not installed"; \
	fi

lint-python:
	@echo "$(BLUE)Linting Python files...$(NC)"
	@if command -v pylint &>/dev/null; then \
		find . -name "*.py" -type f | while read pyfile; do \
			pylint "$$pyfile" || true; \
		done; \
	fi
	@if command -v black &>/dev/null; then \
		black --check . 2>/dev/null || echo "Run 'black .' to format"; \
	fi

# ============================================================================
# 커버리지 타겟
# ============================================================================

coverage:
	@echo "$(BLUE)Generating coverage report...$(NC)"
	@if command -v pytest &>/dev/null; then \
		pytest tests/ --cov=. --cov-report=html --cov-report=term; \
		echo "$(GREEN)Coverage report generated in htmlcov/index.html$(NC)"; \
	else \
		echo "$(RED)ERROR:$(NC) pytest not installed"; \
	fi

# ============================================================================
# 빌드 타겟
# ============================================================================

build: lint test
	@echo "$(BLUE)Building project...$(NC)"
	@mkdir -p dist
	@echo "$(GREEN)[SUCCESS]$(NC) Build completed"

# ============================================================================
# 설치 타겟
# ============================================================================

install:
	@echo "$(BLUE)Installing $(PROJECT_NAME)...$(NC)"
	@if [[ -f setup.py ]]; then \
		$(PYTHON) setup.py install; \
	elif [[ -f pyproject.toml ]]; then \
		$(PYTHON) -m pip install -e .; \
	else \
		echo "$(BLUE)Copying files to appropriate locations...$(NC)"; \
		mkdir -p ~/.local/bin; \
		cp scripts/* ~/.local/bin/; \
		mkdir -p ~/.config/$(PROJECT_NAME); \
		cp config/* ~/.config/$(PROJECT_NAME)/; \
	fi
	@echo "$(GREEN)[SUCCESS]$(NC) Installation completed"

# ============================================================================
# 정리 타겟
# ============================================================================

clean:
	@echo "$(BLUE)Cleaning build artifacts...$(NC)"
	@find . -type d -name "__pycache__" -exec rm -rf {} + 2>/dev/null || true
	@find . -type f -name "*.pyc" -delete
	@find . -type d -name ".pytest_cache" -exec rm -rf {} + 2>/dev/null || true
	@find . -type d -name "htmlcov" -exec rm -rf {} + 2>/dev/null || true
	@rm -rf dist build *.egg-info
	@echo "$(GREEN)[SUCCESS]$(NC) Cleanup completed"

# ============================================================================
# 벤치마크 타겟
# ============================================================================

benchmark:
	@echo "$(BLUE)Running performance benchmarks...$(NC)"
	@if [[ -f scripts/benchmark.sh ]]; then \
		bash scripts/benchmark.sh; \
	else \
		echo "$(RED)benchmark.sh not found$(NC)"; \
	fi

# ============================================================================
# 보안 타겟
# ============================================================================

security:
	@echo "$(BLUE)Running security checks...$(NC)"
	@if command -v bandit &>/dev/null; then \
		bandit -r . -ll; \
	fi
	@if command -v git-secrets &>/dev/null; then \
		git secrets scan; \
	fi
	@echo "$(GREEN)[SUCCESS]$(NC) Security check completed"

# ============================================================================
# 체크 타겟 (모든 검사 실행)
# ============================================================================

check: lint test coverage security
	@echo ""
	@echo "$(GREEN)================================$(NC)"
	@echo "$(GREEN)All checks passed successfully!$(NC)"
	@echo "$(GREEN)================================$(NC)"

# ============================================================================
# 문서 타겟
# ============================================================================

docs:
	@echo "$(BLUE)Generating documentation...$(NC)"
	@mkdir -p docs
	@if command -v sphinx-build &>/dev/null; then \
		sphinx-build -b html docs docs/_build/html; \
		echo "$(GREEN)Documentation generated in docs/_build/html$(NC)"; \
	else \
		echo "$(BLUE)Creating documentation index...$(NC)"; \
		cat > docs/index.md << 'EOF'; \
# $(PROJECT_NAME) Documentation\n\n\
## 주요 문서\n\
- [README](../README.md)\n\
- [설치 가이드](../INSTALLATION.md)\n\
- [성능 최적화](../PERFORMANCE.md)\n\
- [테스트 전략](../TESTING.md)\n\
- [배포 가이드](../DEPLOYMENT.md)\n\
- [기여 가이드](../CONTRIBUTING.md)\n\
EOF\
	fi

# ============================================================================
# 버전 타겟
# ============================================================================

version:
	@echo "$(PROJECT_NAME) v$(VERSION)"

tag-release:
	@echo "$(BLUE)Creating release tag v$(VERSION)...$(NC)"
	@git tag -a v$(VERSION) -m "Release v$(VERSION)"
	@git push origin v$(VERSION)
	@echo "$(GREEN)[SUCCESS]$(NC) Tag created: v$(VERSION)"

# ============================================================================
# 개발 편의 타겟
# ============================================================================

format:
	@echo "$(BLUE)Formatting code...$(NC)"
	@if command -v black &>/dev/null; then \
		black .; \
	fi
	@if command -v shfmt &>/dev/null; then \
		find . -name "*.sh" -exec shfmt -i 4 -w {} \;; \
	fi

watch:
	@echo "$(BLUE)Watching for changes...$(NC)"
	@while true; do \
		inotifywait -e modify -r . --exclude '\.git|__pycache__|\.pyc' && \
		clear && make check; \
	done

# ============================================================================
# CI/CD 통합 타겟
# ============================================================================

ci: clean lint test coverage
	@echo "$(GREEN)CI pipeline completed successfully$(NC)"

# ============================================================================
# 기본 타겟
# ============================================================================

.DEFAULT_GOAL := help

# ============================================================================
# Silent rules
# ============================================================================

.SILENT: help version
